-- ============================================================
-- EDUCAÇÃO ESPECIAL — tabela + import + RPCs (baixo egress)
-- Gerado a partir dos 2 Excel (16-06). Rode no SQL Editor do Supabase (main).
-- ============================================================
DROP TABLE IF EXISTS educacao_especial CASCADE;
CREATE TABLE educacao_especial (
  ra               text PRIMARY KEY,
  unidade          text,
  curso            text,
  serie            text,
  turma            text,
  aluno            text,
  status           text,
  num_formularios  int,
  respostas        int,
  questoes         int,
  pct              numeric
);
CREATE INDEX ix_ee_unidade ON educacao_especial (unidade);
CREATE INDEX ix_ee_status  ON educacao_especial (status);

-- Leitura pública (anon) como as demais tabelas do MAPA — sem RLS bloqueando.
ALTER TABLE educacao_especial DISABLE ROW LEVEL SECURITY;


-- RPC 1: resumo geral + por unidade (compacto)
CREATE OR REPLACE FUNCTION ee_resumo() RETURNS json LANGUAGE sql STABLE AS $$
  SELECT json_build_object(
    'geral', (SELECT json_build_object(
        'total', count(*),
        'avaliados', count(*) FILTER (WHERE status='Com respostas'),
        'pendentes', count(*) FILTER (WHERE status='Sem respostas'),
        'respostas', coalesce(sum(respostas),0),
        'questoes',  coalesce(sum(questoes),0),
        'unidades',  count(distinct unidade)
      ) FROM educacao_especial),
    'por_unidade', coalesce((SELECT json_agg(json_build_array(unidade,total,avaliados,pendentes)) FROM (
        SELECT unidade,
               count(*) total,
               count(*) FILTER (WHERE status='Com respostas') avaliados,
               count(*) FILTER (WHERE status='Sem respostas') pendentes
        FROM educacao_especial GROUP BY unidade ORDER BY unidade) u), '[]'::json)
  );
$$;

-- RPC 2: alunos (arrays), filtrável por unidade/status
CREATE OR REPLACE FUNCTION ee_alunos(p_unidade text DEFAULT NULL, p_status text DEFAULT NULL)
RETURNS json LANGUAGE sql STABLE AS $$
  SELECT coalesce(json_agg(json_build_array(
           unidade,serie,turma,ra,aluno,status,num_formularios,respostas,questoes,pct)), '[]'::json)
  FROM (
    SELECT * FROM educacao_especial
    WHERE (p_unidade IS NULL OR unidade = p_unidade)
      AND (p_status  IS NULL OR status  = p_status)
    ORDER BY unidade,serie,turma,aluno
  ) s;
$$;

GRANT SELECT ON educacao_especial TO anon, authenticated;
GRANT EXECUTE ON FUNCTION ee_resumo() TO anon, authenticated;
GRANT EXECUTE ON FUNCTION ee_alunos(text,text) TO anon, authenticated;
